import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Pi — The Radically Extensible Terminal Coding Agent","description":"","frontmatter":{"title":"Pi — The Radically Extensible Terminal Coding Agent","status":"complete"},"headers":[],"relativePath":"research/agents/pi-coding-agent/index.md","filePath":"research/agents/pi-coding-agent/index.md"}'),i={name:"research/agents/pi-coding-agent/index.md"};function o(r,e,l,p,d,c){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="pi-coding-agent" tabindex="-1">Pi Coding Agent <a class="header-anchor" href="#pi-coding-agent" aria-label="Permalink to &quot;Pi Coding Agent&quot;">​</a></h1><blockquote><p>&quot;If I don&#39;t need it, it won&#39;t be built.&quot; — A minimal, radically extensible terminal coding agent that ships four tools and lets extensions handle everything else.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Pi (<code>@mariozechner/pi-coding-agent</code>) is a terminal-based coding agent created by <strong>Mario Zechner</strong> (@badlogic), the well-known open-source developer behind the libGDX game framework. Pi was born from frustration with Claude Code&#39;s growing complexity — Mario described it as a tool that &quot;turned into a spaceship with 80% of functionality I have no use for.&quot; Pi takes the opposite approach: an aggressively minimal core with a powerful extension system that lets users build exactly the features they need.</p><p>The project lives in a monorepo (<code>pi-mono</code>) organized as seven packages, each independently publishable to npm. The coding agent itself is just one package that composes the others. The website URL — shittycodingagent.ai — captures the tongue-in-cheek philosophy: this is intentionally not a polished product, it&#39;s a set of primitives for people who want control.</p><p>Pi&#39;s core philosophy is <strong>primitives over features</strong>. Where other agents build in MCP support, sub-agents, plan modes, permission systems, and background tasks, Pi deliberately omits all of these from the core. Instead, it provides an extension API powerful enough that each of these can be (and has been) implemented as a community package. This keeps the core simple, the prompt cache stable, and the behavior predictable.</p><h3 id="what-makes-pi-special" tabindex="-1">What Makes Pi Special <a class="header-anchor" href="#what-makes-pi-special" aria-label="Permalink to &quot;What Makes Pi Special&quot;">​</a></h3><ol><li><strong>Four tools, infinite extensibility</strong> — Ships with only <code>read</code>, <code>write</code>, <code>edit</code>, and <code>bash</code>. Everything else is an extension.</li><li><strong>Monorepo architecture</strong> — Seven packages that separate concerns cleanly: LLM API, agent runtime, TUI, coding agent, web UI, Slack bot, GPU pod management.</li><li><strong>Cross-provider LLM API</strong> — <code>pi-ai</code> unifies 15+ providers behind a single interface with context handoff between providers.</li><li><strong>Tree-structured sessions</strong> — JSONL files with parent IDs enabling in-place branching, navigation, and fork operations.</li><li><strong>Skills system</strong> — On-demand capability packages following the Agent Skills standard (agentskills.io) for progressive context disclosure.</li><li><strong>Message queue</strong> — Submit steering messages or follow-ups while the agent works, with configurable delivery modes.</li><li><strong>Anti-feature-creep philosophy</strong> — Deliberate omissions (no MCP, no sub-agents, no plan mode, no permissions) are a feature, not a limitation.</li></ol><h2 id="key-stats" tabindex="-1">Key Stats <a class="header-anchor" href="#key-stats" aria-label="Permalink to &quot;Key Stats&quot;">​</a></h2><ul><li><strong>Language</strong>: TypeScript (monorepo, 7 packages)</li><li><strong>License</strong>: MIT</li><li><strong>Creator</strong>: Mario Zechner (@badlogic)</li><li><strong>Repository</strong>: github.com/badlogic/pi-mono</li><li><strong>Website</strong>: shittycodingagent.ai</li><li><strong>Default tools</strong>: 4 (read, write, edit, bash)</li><li><strong>LLM providers</strong>: 15+ via pi-ai</li><li><strong>Modes</strong>: 4 (Interactive, Print/JSON, RPC, SDK)</li><li><strong>Package ecosystem</strong>: npm keyword <code>pi-package</code></li></ul><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a Glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a Glance&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>pi-mono/</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                         packages/                                │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│  ┌──────────────┐  ┌──────────────────┐  ┌──────────────────┐  │</span></span>
<span class="line"><span>│  │    pi-ai     │  │  pi-agent-core   │  │     pi-tui       │  │</span></span>
<span class="line"><span>│  │  Unified LLM │  │  Agent runtime,  │  │  Terminal UI,    │  │</span></span>
<span class="line"><span>│  │  API, 15+    │──│  tool calling,   │──│  differential    │  │</span></span>
<span class="line"><span>│  │  providers   │  │  state, events   │  │  rendering       │  │</span></span>
<span class="line"><span>│  └──────────────┘  └──────────────────┘  └──────────────────┘  │</span></span>
<span class="line"><span>│          │                   │                     │             │</span></span>
<span class="line"><span>│          ▼                   ▼                     ▼             │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │                  pi-coding-agent (CLI)                     │  │</span></span>
<span class="line"><span>│  │  4 tools: read, write, edit, bash                         │  │</span></span>
<span class="line"><span>│  │  Extensions · Skills · Packages · 4 Modes                 │  │</span></span>
<span class="line"><span>│  └───────────────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│  ┌──────────────┐  ┌──────────────────┐  ┌──────────────────┐  │</span></span>
<span class="line"><span>│  │   pi-web-ui  │  │      pi-mom      │  │     pi-pods      │  │</span></span>
<span class="line"><span>│  │  Web chat    │  │  Slack bot that   │  │  CLI for vLLM    │  │</span></span>
<span class="line"><span>│  │  components  │  │  delegates to pi  │  │  on GPU pods     │  │</span></span>
<span class="line"><span>│  └──────────────┘  └──────────────────┘  └──────────────────┘  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="what-pi-deliberately-does-not-have-built-in" tabindex="-1">What Pi Deliberately Does NOT Have Built-in <a class="header-anchor" href="#what-pi-deliberately-does-not-have-built-in" aria-label="Permalink to &quot;What Pi Deliberately Does NOT Have Built-in&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Pi&#39;s Alternative</th></tr></thead><tbody><tr><td>MCP support</td><td>Use skills with CLI tools and READMEs, or build via extension</td></tr><tr><td>Sub-agents</td><td>Spawn pi instances via tmux, or build via extension</td></tr><tr><td>Permission popups</td><td>Run in container, or build via extension</td></tr><tr><td>Plan mode</td><td>Write plans to files, or build via extension</td></tr><tr><td>Built-in to-dos</td><td>Use TODO.md, or build via extension</td></tr><tr><td>Background bash</td><td>Use tmux</td></tr></tbody></table><p>Every deliberate omission has a simple workaround and can be fully implemented via the extension API. This is the core design insight: <strong>the extension system IS the feature set</strong>.</p><h2 id="ecosystem-highlights" tabindex="-1">Ecosystem Highlights <a class="header-anchor" href="#ecosystem-highlights" aria-label="Permalink to &quot;Ecosystem Highlights&quot;">​</a></h2><ul><li><strong>Active Discord community</strong> with real-time discussion and package sharing</li><li><strong>Third-party packages</strong>: pi-skills, pi-messenger, pi-mcp-adapter, pi-web-access</li><li><strong>Comparison projects</strong>: pi-vs-claude-code benchmarking repos</li><li><strong>Curated list</strong>: awesome-pi-agent</li><li><strong>Multi-agent integration</strong>: Works with orchestrators like Overstory and Agent of Empires</li><li><strong>Install from anywhere</strong>: <code>pi install npm:@foo/pi-tools</code> or <code>pi install git:github.com/user/repo</code></li></ul><h2 id="files-in-this-research" tabindex="-1">Files in This Research <a class="header-anchor" href="#files-in-this-research" aria-label="Permalink to &quot;Files in This Research&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Description</th></tr></thead><tbody><tr><td><a href="./architecture.html">architecture.md</a></td><td>Monorepo structure, pi-ai provider system, pi-agent-core, pi-tui, the 4 modes</td></tr><tr><td><a href="./agentic-loop.html">agentic-loop.md</a></td><td>Minimal agent loop, message queue, steering vs follow-up, compaction</td></tr><tr><td><a href="./tool-system.html">tool-system.md</a></td><td>The 4 default tools, extension API, skills system, packages, why no MCP</td></tr><tr><td><a href="./context-management.html">context-management.md</a></td><td>AGENTS.md/SYSTEM.md, compaction, skills, prompt templates, dynamic context, sessions</td></tr><tr><td><a href="./unique-patterns.html">unique-patterns.md</a></td><td>Radical extensibility, deliberate omissions, cross-provider handoff, tree sessions</td></tr><tr><td><a href="./benchmarks.html">benchmarks.md</a></td><td>Community adoption metrics, ecosystem growth, comparison projects</td></tr><tr><td><a href="./references.html">references.md</a></td><td>Source repos, blog posts, Discord, npm packages, documentation</td></tr></tbody></table>`,19)])])}const m=t(i,[["render",o]]);export{g as __pageData,m as default};
